1481 /// xor (is_fpclass x, mask0), (is_fpclass x, mask1)
1482 ///     -> is_fpclass x, (mask0 ^ mask1)
1483 Instruction *InstCombinerImpl::foldLogicOfIsFPClass(BinaryOperator &BO,
1484                                                     Value *Op0, Value *Op1) {
