1394     // and (fcmp ord x, 0), (fcmp u* fabs(x), inf) -> fcmp o* x, inf
1395     if (Value *Left = matchIsFiniteTest(Builder, LHS, RHS))
1396       return Left;
1397     if (Value *Right = matchIsFiniteTest(Builder, RHS, LHS))
1398       return Right;
